);
ALTER TABLE strata ADD COLUMN IF NOT EXISTS study TEXT;                                             -- FK to the parent Study.
ALTER TABLE strata ADD COLUMN IF NOT EXISTS stratum_label TEXT;                                     -- Short label used in CaseCells (e.g. small, large, dept-A).
ALTER TABLE strata ADD COLUMN IF NOT EXISTS description TEXT;                                       -- Plain-language description of what defines this stratum.
COMMENT ON TABLE strata IS 'Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.';
COMMENT ON COLUMN strata.stratum_id IS 'Unique slug (e.g. kidney-1986-small, kidney-1986-large).';
COMMENT ON COLUMN strata.study IS 'FK to the parent Study.';
COMMENT ON COLUMN strata.stratum_label IS 'Short label used in CaseCells (e.g. small, large, dept-A).';
COMMENT ON COLUMN strata.description IS 'Plain-language description of what defines this stratum.';

-- ----------------------------------------------------------------------------
-- CaseCells: Table: CaseCells — the raw leaves of the DAG. One row per (study, stratum, treatment) combination recording the aggregate count of successes and total cases. Every derived fact in the model traces back to these numbers. Nothing above this row is a raw input.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS case_cells (
  case_cell_id                        TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-small-A).
);
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS study TEXT;                                         -- FK to the parent Study.
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS stratum_label TEXT;                                 -- The stratum this cell belongs to (matches Strata.StratumLabel).
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS treatment_label TEXT;                               -- The treatment applied in this cell (matches Treatments.TreatmentLabel).
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS successes INTEGER;                                  -- Number of patients in this cell who had a successful outcome. RAW INPUT — never derived.
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS cases INTEGER;                                      -- Total number of patients in this cell. RAW INPUT — never derived.
COMMENT ON TABLE case_cells IS 'Table: CaseCells — the raw leaves of the DAG. One row per (study, stratum, treatment) combination recording the aggregate count of successes and total cases. Every derived fact in the model traces back to these numbers. Nothing above this row is a raw input.';
COMMENT ON COLUMN case_cells.case_cell_id IS 'Unique slug (e.g. kidney-1986-small-A).';
COMMENT ON COLUMN case_cells.study IS 'FK to the parent Study.';
COMMENT ON COLUMN case_cells.stratum_label IS 'The stratum this cell belongs to (matches Strata.StratumLabel).';
COMMENT ON COLUMN case_cells.treatment_label IS 'The treatment applied in this cell (matches Treatments.TreatmentLabel).';
COMMENT ON COLUMN case_cells.successes IS 'Number of patients in this cell who had a successful outcome. RAW INPUT — never derived.';
COMMENT ON COLUMN case_cells.cases IS 'Total number of patients in this cell. RAW INPUT — never derived.';

-- ----------------------------------------------------------------------------
-- StratumSummaries: Table: StratumSummaries — one row per (study, stratum, treatment). Computes the success rate WITHIN each stratum for each treatment. This is the stratified view that contradicts the pooled conclusion when a Simpson's Paradox reversal is present. Each row belongs to both a Stratum and a Treatment in the same Study.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS stratum_summaries (
  stratum_summary_id                  TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-small-A).
);
ALTER TABLE stratum_summaries ADD COLUMN IF NOT EXISTS study TEXT;                                  -- FK to the parent Study.
ALTER TABLE stratum_summaries ADD COLUMN IF NOT EXISTS stratum_label TEXT;                          -- Which stratum (matches Strata.StratumLabel).
ALTER TABLE stratum_summaries ADD COLUMN IF NOT EXISTS treatment_label TEXT;                        -- Which treatment (matches Treatments.TreatmentLabel).
COMMENT ON TABLE stratum_summaries IS 'Table: StratumSummaries — one row per (study, stratum, treatment). Computes the success rate WITHIN each stratum for each treatment. This is the stratified view that contradicts the pooled conclusion when a Simpson''s Paradox reversal is present. Each row belongs to both a Stratum and a Treatment in the same Study.';
COMMENT ON COLUMN stratum_summaries.stratum_summary_id IS 'Unique slug (e.g. kidney-1986-small-A).';
COMMENT ON COLUMN stratum_summaries.study IS 'FK to the parent Study.';
COMMENT ON COLUMN stratum_summaries.stratum_label IS 'Which stratum (matches Strata.StratumLabel).';
COMMENT ON COLUMN stratum_summaries.treatment_label IS 'Which treatment (matches Treatments.TreatmentLabel).';

-- ----------------------------------------------------------------------------
-- ModelSummary: Table: ModelSummary — one row describing the epistemic coverage of this entire model instance. Aggregates across all TreatmentRankings to witness how many studies were examined, how many showed a full reversal, how many were explained, and the average paradox strength. The model holds a mirror to itself.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS model_summary (
  model_summary_id                    TEXT                 PRIMARY KEY          -- Unique identifier for this model instance.
);
COMMENT ON TABLE model_summary IS 'Table: ModelSummary — one row describing the epistemic coverage of this entire model instance. Aggregates across all TreatmentRankings to witness how many studies were examined, how many showed a full reversal, how many were explained, and the average paradox strength. The model holds a mirror to itself.';
COMMENT ON COLUMN model_summary.model_summary_id IS 'Unique identifier for this model instance.';

-- ----------------------------------------------------------------------------
-- StratumVariables: Table: StratumVariables — one row per study, naming the variable that defines the strata and describing its causal role. A confounder affects both treatment assignment AND outcome; a mediator is downstream of treatment; a contested variable is one where the causal role is disputed. IsConfounder is derived from these two boolean flags.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS stratum_variables (
  stratum_variable_id                 TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-stone-size).
);
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS study TEXT;                                  -- FK to the parent Study.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS variable_name TEXT;                          -- The name of the stratifying variable (e.g. stone_size, department, age_group).
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS causal_role TEXT;                            -- The variable's causal role: 'confounder' (affects both assignment and outcome), 'mediator' (downstream of treatment), 'contested' (causal role disputed), 'unknown'.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS affects_treatment_assignment BOOLEAN;        -- TRUE if this variable causally influences which treatment a patient receives. Required for confounding.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS affects_outcome BOOLEAN;                     -- TRUE if this variable causally influences the outcome independently of treatment. Required for confounding.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS mechanism_note TEXT;                         -- Plain-language description of how this variable creates the confounding: why it affects both assignment and outcome.
COMMENT ON TABLE stratum_variables IS 'Table: StratumVariables — one row per study, naming the variable that defines the strata and describing its causal role. A confounder affects both treatment assignment AND outcome; a mediator is downstream of treatment; a contested variable is one where the causal role is disputed. IsConfounder is derived from these two boolean flags.';
COMMENT ON COLUMN stratum_variables.stratum_variable_id IS 'Unique slug (e.g. kidney-1986-stone-size).';
COMMENT ON COLUMN stratum_variables.study IS 'FK to the parent Study.';
COMMENT ON COLUMN stratum_variables.variable_name IS 'The name of the stratifying variable (e.g. stone_size, department, age_group).';
COMMENT ON COLUMN stratum_variables.causal_role IS 'The variable''s causal role: ''confounder'' (affects both assignment and outcome), ''mediator'' (downstream of treatment), ''contested'' (causal role disputed), ''unknown''.';
COMMENT ON COLUMN stratum_variables.affects_treatment_assignment IS 'TRUE if this variable causally influences which treatment a patient receives. Required for confounding.';
COMMENT ON COLUMN stratum_variables.affects_outcome IS 'TRUE if this variable causally influences the outcome independently of treatment. Required for confounding.';
COMMENT ON COLUMN stratum_variables.mechanism_note IS 'Plain-language description of how this variable creates the confounding: why it affects both assignment and outcome.';

-- ----------------------------------------------------------------------------
-- TreatmentRankings: Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS treatment_rankings (
  treatment_ranking_id                TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-A-vs-B).
);
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS study TEXT;                                 -- FK to the parent Study.
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS treatment_a TEXT;                           -- Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS treatment_b TEXT;                           -- Label for the second treatment in the comparison.
COMMENT ON TABLE treatment_rankings IS 'Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.';
COMMENT ON COLUMN treatment_rankings.treatment_ranking_id IS 'Unique slug (e.g. kidney-1986-A-vs-B).';
COMMENT ON COLUMN treatment_rankings.study IS 'FK to the parent Study.';
COMMENT ON COLUMN treatment_rankings.treatment_a IS 'Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).';
COMMENT ON COLUMN treatment_rankings.treatment_b IS 'Label for the second treatment in the comparison.';

